Author: Kevin Pagano
Description: Microsoft Defender Attack Surface Reduction has audited an operation
EventId: 1134
Channel: Microsoft-Windows-Windows Defender/Operational
Provider: Microsoft-Windows-Windows Defender
Maps:
  -
    Property: UserName
    PropertyValue: "%User%"
    Values:
      -
        Name: User
        Value: "/Event/EventData/Data[@Name=\"User Sid\"]"
  -
    Property: ExecutableInfo
    PropertyValue: "Process: %Process%"
    Values:
      -
        Name: Process
        Value: "/Event/EventData/Data[@Name=\"Process\"]"
  -
    Property: PayloadData1
    PropertyValue: "Action: %ActionType% | Level: %Enforcement%"
    Values:
      -
        Name: ActionType
        Value: "/Event/EventData/Data[@Name=\"Action Type\"]"
      -
        Name: Enforcement
        Value: "/Event/EventData/Data[@Name=\"Enforcement Level\"]"
  -
    Property: PayloadData2
    PropertyValue: "Source: %Source%"
    Values:
      -
        Name: Source
        Value: "/Event/EventData/Data[@Name=\"Source\"]"
  -
    Property: PayloadData3
    PropertyValue: "Target: %Target%"
    Values:
      -
        Name: Target
        Value: "/Event/EventData/Data[@Name=\"Target\"]"
  -
    Property: PayloadData4
    PropertyValue: "Policy Rule ID: %PolicyID%"
    Values:
      -
        Name: PolicyID
        Value: "/Event/EventData/Data[@Name=\"Policy Rule Id\"]"
  -
    Property: PayloadData5
    PropertyValue: "Versions - Product: %ProdVer% | Engine: %EngVer%"
    Values:
      -
        Name: ProdVer
        Value: "/Event/EventData/Data[@Name=\"Product Version\"]"
      -
        Name: EngVer
        Value: "/Event/EventData/Data[@Name=\"Engine Version\"]"

# Documentation:
# https://raw.githubusercontent.com/nasbench/EVTX-ETW-Resources/refs/heads/main/ETWProvidersCSVs/Internal/Microsoft-Windows-Windows%20Defender.csv
